import React, { useEffect, useState } from "react";
import axios from "axios";

const OrdersPage = () => {
  const [orders, setOrders] = useState([]);

  useEffect(() => {
    fetchOrders();
  }, []);

  const fetchOrders = async () => {
    try {
      const res = await axios.get("http://localhost:5000/orders");
      setOrders(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  const handleCancel = async (orderId) => {
    const reason = prompt("Enter cancellation reason:");
    if (!reason) return;

    try {
      await axios.put(`http://localhost:5000/orders/cancel/${orderId}`, {
        reason
      });
      fetchOrders();
      alert("Order Cancelled Successfully");
    } catch (err) {
      console.log(err);
      alert("Cancel Failed");
    }
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>Your Orders</h2>

      {orders.length === 0 ? (
        <p>No Orders Found</p>
      ) : (
        orders.map((order) => (
          <div
            key={order._id}
            style={{
              border: "1px solid #ddd",
              borderRadius: "10px",
              marginBottom: "20px",
              padding: "15px",
              position: "relative",
              background: "#fafafa",
            }}
          >
            {/* Cancel Button */}
            <button
              style={{
                position: "absolute",
                top: "10px",
                right: "10px",
                background: "#ff4d4d",
                color: "#fff",
                border: "none",
                padding: "6px 12px",
                borderRadius: "6px",
                cursor: "pointer",
                fontWeight: "600"
              }}
              onClick={() => handleCancel(order._id)}
            >
              Cancel
            </button>

            <h3>Order ID: {order._id}</h3>
            <p>Date: {new Date(order.createdAt).toLocaleString()}</p>
            <p>Status: <b>{order.status}</b></p>

            <h4>Items:</h4>

            {order.items.map((item, i) => (
              <div
                key={i}
                style={{
                  display: "flex",
                  justifyContent: "space-between",
                  alignItems: "center",
                  padding: "10px 0",
                  borderBottom: "1px solid #eee"
                }}
              >
                <div style={{ display: "flex", alignItems: "center" }}>
                  <img
                    src={item.image}
                    alt={item.title}
                    style={{
                      width: "60px",
                      height: "60px",
                      borderRadius: "6px",
                      marginRight: "12px"
                    }}
                  />
                  <div>
                    <p><b>{item.title}</b></p>
                    <p>Qty: {item.quantity}</p>
                  </div>
                </div>

                <p>₹{item.price * item.quantity}</p>
              </div>
            ))}

            <h3 style={{ textAlign: "right", marginTop: "10px" }}>
              Total: ₹{order.totalAmount}
            </h3>
          </div>
        ))
      )}
    </div>
  );
};

export default OrdersPage;
